package com.food_application.Servlet;
import java.io.*;import org.json.*;import com.food_application.DAOApplication.NotificationDAOImpl;import com.food_application.model.*;import jakarta.servlet.annotation.WebServlet;import jakarta.servlet.http.*;
@WebServlet("/notifications") public class NotificationServlet extends HttpServlet { protected void doGet(HttpServletRequest q,HttpServletResponse r)throws IOException{HttpSession s=q.getSession(false);User u=s==null?null:(User)s.getAttribute("loggedUser");if(u==null){r.setStatus(401);return;}NotificationDAOImpl d=new NotificationDAOImpl();JSONObject out=new JSONObject();out.put("unreadCount",d.getUnreadCount(u.getUserId()));JSONArray a=new JSONArray();for(Notification n:d.getCustomerNotifications(u.getUserId(),0,20)){JSONObject x=new JSONObject();x.put("id",n.getNotificationId());x.put("orderId",n.getOrderId());x.put("title",n.getTitle());x.put("message",n.getMessage());x.put("read",n.isRead());x.put("createdAt",n.getCreatedAt().toString());a.put(x);}out.put("notifications",a);r.setContentType("application/json");r.getWriter().print(out);}}
